// ORGANIZATION & WORKSPACE TYPES
// ============================================

export type OrganizationRole = 'owner' | 'admin' | 'member' | 'viewer';
export type WorkspaceRole = 'owner' | 'admin' | 'editor' | 'viewer';
export type OrganizationType = 'company' | 'agency';
export type WorkspaceType = 'personal' | 'company' | 'client';

export interface Organization {
  id: string;
  name: string;
  slug: string;
  description: string | null;
  logoUrl: string | null;
  website: string | null;
  orgType: OrganizationType;
  settings: Record<string, unknown> | null;
  planType: PlanType;
  planLimits: Record<string, unknown> | null;
  createdAt: Date;
  updatedAt: Date;
}

export interface OrganizationMember {
  id: string;
  organizationId: string;
  userId: string;
  role: OrganizationRole;
  permissions: Record<string, unknown> | null;
  invitationStatus: 'pending' | 'accepted' | 'declined';
  invitedBy: string | null;
  invitedAt: Date | null;
  joinedAt: Date;
  user?: User;
}

export interface Workspace {
  id: string;
  organizationId: string;
  name: string;
  slug: string;
  description: string | null;
  iconUrl: string | null;
  workspaceType: WorkspaceType;
  agencyClientId: string | null;
  settings: Record<string, unknown> | null;
  isActive: boolean;
  createdAt: Date;
  updatedAt: Date;
  organization?: Organization;
  linkedinProfile?: LinkedInProfileDraft;
  linkedinPages?: LinkedInPageDraft[];
}

export interface WorkspaceMember {
  id: string;
  workspaceId: string;
  userId: string;
  role: WorkspaceRole;
  permissions: Record<string, unknown> | null;
  joinedAt: Date;
  user?: User;
}

